const body = $input.first().json.body || $input.first().json;
const nombre = body.payload?.nombre || body.nombre || 'Cliente';
const email = body.payload?.email || body.email || '';
const telefono = body.payload?.telefono || body.telefono || '';
const rut = body.payload?.rut || body.rut || '';
const clienteId = body.key || body.cliente_id || '';
const tempPassword = Math.random().toString(36).slice(-8);

return [{ json: { cliente_id: clienteId, nombre, email, telefono, rut, temp_password: tempPassword } }];

const prev = $('Generar Credenciales').first().json;
const nombre = prev.nombre || 'Estimado/a cliente';
const rut = prev.rut || '';
const clave = prev.temp_password || '';

