ospace">${clave}</div></div></td></tr></table><p style="color:#e2e8f0;font-size:14px;line-height:1.7;margin:0 0 12px 0">Por seguridad, le recomendamos cambiar su clave en el primer acceso.</p><p style="color:#718096;font-size:13px;margin:0 0 32px 0">Si tiene alguna consulta sobre el acceso al portal, no dude en contactarnos.</p><table cellpadding="0" cellspacing="0" style="margin:0 auto"><tr><td style="background:linear-gradient(135deg,#00d2ff,#0099cc);border-radius:8px;padding:14px 32px;text-align:center"><a href="mailto:contacto@toxirodigital.cloud" style="color:#ffffff;font-size:14px;font-weight:600;text-decoration:none">Contactar al Estudio</a></td></tr></table></td></tr><tr><td style="background-color:#0f1117;border-radius:0 0 12px 12px;padding:24px 40px;text-align:center;border-top:1px solid #1a1f2e"><p style="color:#4a5568;font-size:12px;margin:0 0 4px 0">© 2026 Toxiro Abogados · contacto@toxirodigital.cloud</p><p style="color:#2d3748;font-size:11px;margin:0">Este correo contiene información confidencial destinada exclusivamente al destinatario.</p></td></tr></table></td></tr></table></body></html>`;

return [{ json: { html, to: prev.email, nombre, rut, clave } }];
